return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n > 1);','language'=>'fr_FR','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2025-05-13 14:46:39+0000','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Veuillez mettre à jour l’extension TranslatePress - Multilingual vers la version %1$s ou supérieure pour que %2$s fonctionne correctement.','Please install and activate the TranslatePress - Multilingual plugin'=>'Veuillez installer et activer l’extension TranslatePress - Multilingual','Install & Activate'=>'Installer et activer','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Veuillez mettre à jour TranslatePress - Multilingual vers la version %2$s ou ultérieure. La version actuellement installée de TranslatePress - Multilingual n’est plus compatible avec la version actuelle de %1$s.','All TranslatePress functionalities are disabled until then.'=>'Toutes les fonctionnalités de TranslatePress sont désactivées jusqu’alors.','Update Now'=>'Mettre à jour maintenant','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Cette extension complémentaire TranslatePress a été intégrée à l’extension principale et n’est plus utilisée. Vous pouvez la supprimer.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> nécessite au moins PHP version 5.6.20+. C’est le <a href="%s">minimum nécessaire pour la dernière version de WordPress</a>. Veuillez contacter l’administrateur de votre serveur pour mettre à niveau votre version de PHP.','Advanced'=>'Avancé','Settings saved.'=>'Réglages enregistrés.','Are you sure you want to remove this item?'=>'Confirmez-vous vouloir retirer cet élément ?','Remove'=>'Supprimer','Add'=>'Ajouter','Select...'=>'Sélectionner...','[%s] Low TranslatePress AI Words'=>'[%s] Niveau faible de mots TranslatePress AI','upgrade your plan or get extra AI Words'=>'mettre à niveau votre formule ou obtenir des mots d’IA supplémentaires','upgrade your plan'=>'mettre à niveau votre formule','TranslatePress AI words are running low on your site.'=>'Les mots TranslatePress AI de votre site sont presque épuisés.','Current status: %s words remaining'=>'État actuel : %s mots restants','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Une fois les mots d’IA restants épuisés, la traduction automatique via TranslatePress AI sera mise en pause.','To continue translating your content, please %1$s over at %2$s'=>'Pour continuer à traduire votre contenu, veuillez %1$s sur %2$s','Manage Notification: %s'=>'Gérer la notification : %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Une nouvelle version de %1$s est disponible. %2$sVoir les détails de la version %3$s%4$s ou %5$smettre à jour maintenant%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Une nouvelle version de %1$s est disponible. %2$sVoir les détails de la version %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Pour activer les mises à jour, veuillez %1$ssaisir votre clé de licence%2$s. Besoin d’une clé de licence ? %3$sAchetez-en une maintenant%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Pour activer les mises à jour, veuillez vous rendre sur la %1$spage de licence%2$s et vérifier que vous disposez d’une licence valide.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Pour activer les mises à jour, votre licence doit être renouvelée. Veuillez vous rendre sur la page %1$sCompte TranslatePress%2$s et vous connecter pour renouveler.','You do not have permission to install plugin updates'=>'Vous n’avez pas les droits suffisants pour installer les mises à jour de l’extension.','Error'=>'Erreur','Your TranslatePress license key is invalid or missing.'=>'Votre clé de licence TranslatePress est invalide ou manquante.','Your license key expired on %s.'=>'Votre clé de licence a expirée le %s.','Your license key has been disabled.'=>'Votre clé de licence a été désactivée.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Votre clé de licence est désactivée pour cette URL. Réactivez-la depuis <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gérer les sites.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Incompatibilité de la clé de licence.</strong> La licence que vous avez saisie ne correspond pas à la version de TranslatePress que vous avez installée.</p><p>Veuillez vérifier que vous avez installé la version correspondant à votre licence depuis votre compte TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Si vous avez uniquement installé l\'extension gratuite mais que vous avez ajouté une licence payante, veuillez installer l\'extension payante depuis votre compte TranslatePress.','Your license key has reached its activation limit.'=>'Votre clé de licence a atteint sa limite d’activation.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Faites évoluer votre plan pour ajouter plus de sites. %1$sMettre à niveau maintenant%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Ce site web est déjà activé sous une licence gratuite. Chaque site web ne peut utiliser qu\'une seule licence gratuite.','An error occurred, please try again.'=>'Une erreur est survenue, veuillez réessayer.','You have successfully activated your license'=>'Vous avez bien activé votre licence','Others'=>'Autres','Restrict by Language'=>'Limitation par langue','Exclude from Language'=>'Exclure de la langue','Restrict element to language'=>'Limiter l’élément à la langue','Show this element only in one language.'=>'Afficher cet élément uniquement dans une seule langue.','Enable translation'=>'Activer la traduction','Allow translation to the corresponding language only if the content is written in the default language.'=>'Autoriser la traduction dans la langue correspondante uniquement si le contenu est rédigé dans la langue par défaut.','Select language'=>'Sélectionner une langue','Choose in which language to show this element.'=>'Choisir dans quelle langue montrer cet élément.','Exclude element from language'=>'Exclure l’élément de la langue','Exclude this element from specific languages.'=>'Exclure cet élément de langues spécifiques.','Select languages'=>'Choisir des langues','Choose from which languages to exclude this element.'=>'Choisir parmi quelles langues pour exclure cet élément.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Cet élément sera toujours visible lorsque vous traduisez votre site Web par l’intermédiaire de l’éditeur de traduction.','The content of this element should be written in the default language.'=>'Le contenu de cet élément doit être écrit dans la langue par défaut.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> a rencontré des erreurs SQL. <a href="%s" title="View TranslatePress SQL Errors">Consultez les erreurs</a>.','Automatic translation has been disabled.'=>'La traduction automatique a été désactivée.','Dismiss this notice.'=>'Ignorer ce message.','Logged errors'=>'Erreurs de connexion','These are the most recent 5 errors logged by TranslatePress:'=>'Voici les 5 erreurs les plus récentes enregistrées par TranslatePress :','Yes'=>'Oui','Why are these errors occuring'=>'Pourquoi ces erreurs se produisent-elles','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Si TranslatePress détecte quelque chose d’incorrect lors de l’exécution de requêtes sur votre base de données, il peut désactiver la fonction de traduction automatique afin d’éviter toute charge supplémentaire par Google/DeepL. La traduction automatique doit être activée manuellement, après avoir résolu les problèmes.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Les erreurs SQL détectées peuvent se produire pour diverses raisons, notamment des tables manquantes, des autorisations manquantes pour l’utilisateur SQL pour créer des tables ou effectuer d’autres opérations, des problèmes après la migration du site ou des modifications de la configuration du serveur SQL.','What you can do in this situation'=>'Ce que vous pouvez faire dans cette situation','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Rendez-vous dans Réglages -> TranslatePress -> l\'onglet Général et enregistrez les réglages. Cela régénérera les tables en utilisant vos paramètres SQL actuels. Vérifiez qu\'aucune erreur supplémentaire ne survient lors de la navigation sur votre site web dans une langue traduite. Regardez les horodatages des erreurs pour vous assurer que vous ne voyez pas les anciennes erreurs. Seules les 5 erreurs les plus récentes sont affichées.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Si votre problème n\'est pas résolu, essayez les étapes suivantes :','Create a backup of your database'=>'Créez une sauvegarde de votre base de données','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Créez une copie de chaque table de traduction où vous rencontrez des erreurs. Vous pouvez copier la table dans la même base de données (trp_dictionary_en_us_es_es_COPY par exemple) -- effectuez cette étape uniquement si vous souhaitez conserver les traductions actuelles','Remove the trouble tables by executing the DROP function on them'=>'Retirer les problèmes des tables en exécutant sur elles la fonction DROP','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Rendez-vous dans Réglages -> TranslatePress -> l\'onglet Général et enregistrez les réglages. Cela régénérera les tables en utilisant votre serveur SQL actuel.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copiez le contenu pertinent depuis les tables dupliquées (trp_dictionary_en_us_es_es_COPY par exemple) dans la table nouvellement générée (trp_dictionary_en_us_es_es) -- effectuez cette étape uniquement si vous souhaitez conserver les traductions actuelles','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testez-le pour voir si tout fonctionne. Si quelque chose ne va pas, vous pouvez restaurer la sauvegarde que vous avez faite à la première étape. Vérifiez si d’autres erreurs se produisent lors de la navigation sur votre site Web dans une langue traduite. Regardez les dates des erreurs pour vous assurer que vous ne voyez pas les anciennes erreurs. Seules les 5 erreurs les plus récentes sont affichées.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Si votre problème n\'est toujours pas résolu, essayez de contacter votre hébergeur à propos de vos erreurs. Le problème le plus courant est l\'absence d\'autorisations pour l\'utilisateur SQL, comme l\'autorisation de créer des tables.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Impossible d\'installer. Réessayez depuis <a href="%s" >la page des extensions.</a>','Active'=>'Actif','Permission denied.'=>'Permission refusée.','Invalid nonce.'=>'Nonce non valide.','Settings scope unknown.'=>'Portée des réglages inconnue.','Legacy disabled.'=>'Mode hérité désactivé.','Language Switcher'=>'Sélecteur de langues','Change language to %s'=>'Changer la langue en %s','Automatic Translation'=>'Traduction automatique','DeepL'=>'DeepL','Unsupported languages'=>'Langues non prises en charge','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Le moteur de traduction automatique sélectionné ne prend pas en charge ces langues.<br>Vous pouvez toujours traduire manuellement les pages dans ces langues à l’aide de l’éditeur de traduction.','API key validation failed.'=>'La validation de la clé API a échoué.','API key verification was successful.'=>'La vérification de la clé API a réussi.','Please enter your Google Translate key.'=>'Veuillez saisir votre clé Google Translate.','Please enter your DeepL API key.'=>'Veuillez saisir votre clé API DeepL.','Not TranslatePress onboarding page.'=>'Page d’intégration TranslatePress non reconnue.','Step %s does not exist'=>'L’étape %s n’existe pas','Welcome'=>'Bienvenue','Add Languages'=>'Ajouter des langues','Enable Addons'=>'Activer les extensions','Finalize'=>'Finaliser','Exit Setup'=>'Quitter la configuration','Upgrade'=>'Mettre à niveau','Nothing here'=>'Rien ici','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Votre licence <strong>TranslatePress</strong> est manquante ou invalide. <br/>Veuillez %1$senregistrer votre copie%2$s pour activer la traduction automatique du site web via TranslatePress AI, les extensions premium, les mises à jour automatiques et l’assistance. Besoin d’une clé de licence ? %3$sAchetez-en une maintenant%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Votre licence <strong>TranslatePress</strong> expirera le %1$s. Veuillez %2$srenouveler votre licence%3$s pour continuer à bénéficier des traductions automatiques via TP AI, des extensions premium, des téléchargements de produits et des mises à jour automatiques. %4$sRenouveler maintenant%5$s','Error: '=>'Erreur : ','Something went wrong, please try again.'=>'Il y a eu un problème. Veuillez réessayer.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Votre licence <strong>TranslatePress</strong> a expiré. <br/>Veuillez %1$srenouveler votre licence%2$s pour continuer à bénéficier des traductions automatiques via TranslatePress AI, des extensions premium, des téléchargements de produits et des mises à jour automatiques. %3$sRenouveler maintenant %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Incompatibilité de clé de licence. La licence que vous avez saisie ne correspond pas à la version <strong>%1$s</strong> que vous avez installée. <br/>Veuillez vérifier que vous avez installé la version correcte pour votre licence depuis votre %2$scompte TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Si vous avez uniquement installé l’extension gratuite mais que vous avez ajouté une licence payante, veuillez installer l’extension payante depuis votre compte TranslatePress.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Vous avez atteint la limite d\'activation pour votre licence <strong>%1$s</strong>. <br/>Gérez vos sites actifs depuis %2$s votre compte %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Votre licence est désactivée pour cette URL. Réactivez-la depuis <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gérer les sites.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'La traduction automatique %1$s nécessite une licence active. Veuillez %2$srenouveler%3$s votre licence ou en acheter une nouvelle %4$sici%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Veuillez %1$sentrer%2$s votre clé de licence pour activer la traduction automatique %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Il vous reste moins de 5 000 mots TranslatePress AI. Pour continuer à traduire automatiquement votre site web, veuillez %sacheter des mots AI supplémentaires à prix réduit depuis votre compte%s.',' Error: '=>' Erreur : ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Ce site web est déjà activé sous une licence gratuite. Chaque site web ne peut utiliser qu\'une seule licence gratuite. Veuillez passer à un plan premium pour obtenir plus de mots TranslatePress AI depuis %1$s votre compte %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Vous n\'avez pas de licence valide pour <strong>TranslatePress</strong>. %1$sObtenez-en une gratuitement%2$s pour accéder à TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOUVEAU :</strong> L\'extension <strong>Different Domain per Language</strong> est disponible ! Boostez votre SEO global et créez une expérience locale avec des domaines spécifiques à chaque pays comme .de ou .fr. Passez à <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business ou Developer</a> pour y accéder + d\'autres avantages premium !','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOUVEAU :</strong> L\'extension <strong>Different Domain per Language</strong> est disponible ! Boostez votre SEO global et créez une expérience locale avec des domaines spécifiques à chaque pays comme .de ou .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">En savoir plus</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Le quota quotidien de caractères de traduction automatique a été dépassé. Veuillez consulter la page <strong>TranslatePress -> <a href="%s">Traduction automatique</a></strong> pour plus d’information.','Marketing optin'=>'Opt-in marketing','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Acceptez de recevoir nos notifications de mises à jour de sécurité et de fonctionnalités, ainsi que le suivi diagnostique non sensible.','TranslatePress Preferred User Language'=>'Langue préférée de l\'utilisateur TranslatePress','Preferred language to navigate the site'=>'Langue préférée pour naviguer sur le site','The language is automatically set based by the last visited language by the user.'=>'La langue est automatiquement définie en fonction de la dernière langue visitée par l\'utilisateur.','Always use this language'=>'Utiliser toujours cette langue','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'En cochant ce réglage, la langue préférée restera celle sélectionnée ci-dessus, sans possibilité d\'être modifiée dans le frontend.<br>Cette langue sera utilisée dans différentes opérations telles que l\'envoi d\'e-mails à l\'utilisateur.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Bonjour ! Il semble que vous utilisiez <strong>TranslatePress</strong> depuis un certain temps pour traduire votre site web. C\'est génial ! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Si vous pouvez prendre quelques instants pour le noter sur WordPress.org, cela nous aiderait beaucoup (et boosterait ma motivation).','~ Razvan, developer of TranslatePress'=>'~ Razvan, développeur de TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Noter TranslatePress sur la page de l\'extension WordPress.org','Ok, I will gladly help!'=>'OK, je vais aider avec plaisir !','No, thanks.'=>'Non, merci.','Full Language Names'=>'Noms complets de la langue','Short Language Names'=>'Noms courts de la langue','Flags with Full Language Names'=>'Drapeaux avec noms complets de la langue','Flags with Short Language Names'=>'Drapeaux avec noms courts de la langue','Only Flags'=>'Drapeaux uniquement','Full Language Names No HTML'=>'Noms complets des langues sans HTML','Bottom Right'=>'En bas à droite','Bottom Left'=>'En bas à gauche','Top Right'=>'En haut à droite','Top Left'=>'En haut à gauche','Dark'=>'Sombre','Light'=>'Clair','Deactivate'=>'Désactiver','Activate'=>'Activer','Invalid language code. Please try again.'=>'Code de langue non valide. Veuillez réessayer.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Les codes de langue ne peuvent contenir que les caractères A-Z a-z 0-9 - _. Vérifiez vos codes de langue dans les réglages généraux de TranslatePress.','Error! Duplicate URL slug values.'=>'Erreur ! Slug de l’URL en double.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Vous ne pouvez pas sélectionner deux langues qui ont le même <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">code ISO</a> mais des niveaux de formalité différents, car cela entraînerait des <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">balises hreflang</a> en double.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Langue en double détectée.<br>Chaque langue ne peut être ajoutée qu\'une seule fois pour garantir une gestion précise des traductions.<br> Veuillez modifier l\'entrée de langue en double et réessayer. ','Current Language'=>'Langue actuelle','Opposite Language'=>'Langue opposée','General'=>'Général','Translate Site'=>'Traduction du site','Addons'=>'Modules','License'=>'Licence','Settings'=>'Réglages','Activate License'=>'Activer la licence','Pro Features'=>'Fonctionnalités Pro','Need Help?'=>'Besoin d\'aide ?','Recent community discussions'=>'Discussions récentes de la communauté','Loading...'=>'Chargement...','Unable to load forum posts'=>'Impossible de charger les articles du forum','Ask a Question'=>'Poser une question','View All Topics'=>'Voir tous les sujets','by'=>'par','Have a question?'=>'Vous avez une question ?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Obtenez de l\'aide directement auprès des développeurs de l\'extension, suggérez des améliorations ou partagez votre avis !','Tip for faster help:'=>'Astuce pour obtenir de l\'aide plus rapidement :','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Indiquez ce que vous avez essayé, ce que vous attendiez et ce qui s\'est passé. Les captures d\'écran aident !','Toggle support chat'=>'Activer/désactiver le chat d\'assistance','Ask the community'=>'Demander à la communauté','Close'=>'Fermer','Empty feed response'=>'Réponse vide du flux','Unable to parse feed'=>'Impossible d\'analyser le flux','Just now'=>'À l\'instant','%d hour ago'=>'Il y a %d heure' . "\0" . 'Il y a %d heures','%d day ago'=>'Il y a %d jour' . "\0" . 'Il y a %d jours','Source'=>'Source','Srcset'=>'Srcset','Alt attribute'=>'Attribut Alt','Title attribute'=>'Attribut de titre','Anchor link'=>'Lien d’ancre','Placeholder attribute'=>'Attribut du texte indicatif','Submit attribute'=>'Envoyer l’attribut','Text'=>'Texte','Video Poster'=>'Poster de la vidéo','plural form'=>'forme plurielle','one'=>'un','few'=>'peu','many'=>'beaucoup','other'=>'autre','Saved'=>'Enregistrée','Save'=>'Enregistrer','Saving translation...'=>'Enregistrement de la traduction...','You have unsaved changes!'=>'Vous avez des changements non enregistrés !','Discard changes'=>'Annuler les modifications','Discard All'=>'Tout annuler','Loading Strings...'=>'Chargement des chaînes...','Select string to translate...'=>'Sélectionnez la chaîne à traduire…','Close Editor'=>'Fermer l’éditeur','From'=>'De','To'=>'À','Add Media'=>'Ajouter un média','Other languages'=>'Autres langues','Context'=>'Contexte','View Website As'=>'Voir le site en tant que','Available in our Pro Versions'=>'Disponible dans nos versions PRO','Select or Upload Media'=>'Sélectionnez ou téléversez un fichier','Use this media'=>'Utiliser ce média','Translate'=>'Traduire','Translate entire block element'=>'Traduire un élément de bloc entier','Split block to translate strings individually'=>'Diviser en blocs pour traduire les chaînes individuellement','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Enregistrer les changements pour la traduction. Raccourci : CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Naviguer vers la prochaine chaîne dans la liste déroulante. Raccourci : CTRL(⌘) + ALT + Flèche droite','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Naviguer vers la chaîne précédente dans la liste déroulante. Raccourci : CTRL(⌘) + ALT + Flèche gauche','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Annuler tous les changements. Raccourci : CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Annuler tous les changements pour cette boîte de texte. Pour annuler les changements pour toutes les boîtes de texte utilisez le raccourci : CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Masquer l\'infobulle','Quick Intro'=>'Introduction rapide','Are you sure you want to split this phrase into smaller parts?'=>'Confirmer-vous vouloir couper cette phrase en plusieurs morceaux ?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Cette chaîne n’est pas encore prête pour la traduction. <br>Réessayez dans un moment...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Pour que cette option fonctionne, veuillez mettre à niveau votre navigateur comme le module Other Role dans sa dernière version.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Pour traduire les slugs, veuillez mettre à jour le module SEO Pack dans sa dernière version.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Vous pouvez ajouter une nouvelle langue à partir de <a href="%s">Réglages -> TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Cependant, vous pouvez toujours utiliser TranslatePress pour <strong style="background: #f5fb9d;">modifier les chaînes gettext</strong> disponible dans votre page.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Les chaînes qui sont créées par l’utilisateur ne peuvent pas être modifiées, uniquement celles des thèmes et extensions.','Extra Translation Features'=>'Fonctions de traduction supplémentaires','Support for 130+ Extra Languages'=>'Prise en charge de plus de 130 langues supplémentaires','Access to TranslatePress AI'=>'Accès à TranslatePress AI','Translate SEO Title, Description, Slug'=>'Traduire titre SEO, description et URL','Publish only when translation is complete'=>'Publier uniquement lorsque la traduction est terminée','Translate by Browsing as User Role'=>'Traduire en naviguant en tant que rôle utilisateur','Different Menu Items for each Language'=>'Différents éléments de menus par langue','Automatic User Language Detection'=>'Détection automatique de la langue de l’utilisateur','Upgrade to PRO'=>'Passez à la version PRO','Upgrade to PRO with our biggest discount of the year!'=>'Passez à la version PRO avec notre meilleure remise de l\'année !','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Ce Black Friday, accédez à ces fonctionnalités et plus encore pour une fraction du coût :','No available suggestions'=>'Aucune suggestion disponible','Suggestions from translation memory'=>'Suggestions de la mémoire de traduction','Click to Copy'=>'Cliquez pour copier','Human Translation'=>'Traduction humaine','Machine Translation'=>'Traduction automatique','Text on this page is %s% translated into all languages.'=>'Le texte de cette page est traduit à %s % dans toutes les langues.','%1$s% of text on this page is translated into %2$s.'=>'%1$s % du texte de cette page est traduit en %2$s.','This page is %1$s% translated into %2$s.'=>'Cette page est traduite à %1$s % en %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Le slug que vous essayez de modifier est présent dans d\'autres types de slug : %s%. Le modifier remplacera chaque occurrence, quel que soit le type actuel.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Survolez n\'importe quel texte de la page, cliquez sur %s,<br> puis modifiez la traduction dans la barre latérale.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'N\'oubliez pas d\'enregistrer la traduction. Utilisez le raccourci clavier CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Changez de langue pour voir les modifications de traduction directement sur la page.','Search for any text in this page in the dropdown.'=>'Recherchez n\'importe quel texte de cette page dans le menu déroulant.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Votre licence %s a <span class="trp-license-status-emphasized">expiré</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Renouvelez votre licence pour continuer à bénéficier de l\'accès à TranslatePress AI, aux modules complémentaires premium, aux mises à jour automatiques et au support.','Renew Now'=>'Renouveler maintenant','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Ce Black Friday, renouvelez votre licence à un prix spécial</strong> pour continuer à bénéficier de l\'accès aux téléchargements de produits, aux mises à jour automatiques et au support.','Get Deal'=>'Obtenir l\'offre','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Votre licence %s a été <span class="trp-license-status-emphasized">remboursée</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Achetez une nouvelle licence pour continuer à bénéficier de l\'accès à TranslatePress AI, aux modules complémentaires premium, aux mises à jour automatiques et au support.','Purchase a new license'=>'Acheter une nouvelle licence','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Votre licence %s est <span class="trp-license-status-emphasized">manquante ou invalide</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Saisissez une licence valide pour bénéficier de l\'accès à TranslatePress AI, aux modules complémentaires premium, aux mises à jour automatiques et au support. Besoin d\'une clé de licence ? %1$sAchetez-en une maintenant%2$s','Enter a valid license'=>'Saisir une licence valide','Slugs'=>'Slugs','Meta Information'=>'Méta-information','String List'=>'Liste de chaînes','Gettext Strings'=>'Chaînes gettext','Images'=>'Images','Videos'=>'Vidéos','Audios'=>'Audio','Dynamically Added Strings'=>'Chaînes ajoutées dynamiquement','Translation Editor'=>'Éditeur de traduction','Edit translations by visually selecting them on each site page'=>'Modifiez les traductions en les sélectionnant visuellement sur chaque page du site.','String Translation'=>'Traduction de chaînes','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Modifier les traductions de slug d\'URL, d\'extensions et de thème (e-mails, formulaires, etc.)','Current User'=>'Utilisateur/utilisatrice actuel','Logged Out'=>'Déconnecté','Translate Page'=>'Traduire la page','Add a New Language'=>'Ajouter une nouvelle langue','Get a Free AI License'=>'Obtenir une licence IA gratuite','Your License is Invalid'=>'Votre licence est invalide','Get More AI Words (%d left)'=>'Obtenir plus de mots IA (%d restants)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Ouvre l\'article dans l\'éditeur de traduction. L\'article doit préalablement être enregistré comme brouillon ou publié.','Security check'=>'Vérification de sécurité','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>AVERTISSEMENT :</strong> certaines chaînes ont éventuellement des caractères mal encodés. Cela peut entraîner la rupture des requêtes, rendant la page non traduite en ligne. Pensez à vérifier les chaînes suivantes ou leur méthode d’exportation.','TranslatePress data update'=>'Mise à jour des données de TranslatePress','We need to update your translations database to the latest version.'=>'Nous devons mettre à jour votre base de données de traductions vers la dernière version.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'La mise à jour permettra de modifier les traductions du texte localisé des extensions et du thème. La traduction existante continuera de fonctionner comme prévu.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'IMPORTANT : il est fortement recommandé de sauvegarder la base de données au préalable !\\nVoulez-vous vraiment continuer ?','Run the updater'=>'Lancer la mise à jour','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'La mise à jour permettra de modifier les traductions des slugs. La traduction existante continuera de fonctionner comme prévu.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Veuillez activer l\'extension SEO depuis <br/>WordPress -> Réglages -> TranslatePress -> section Extensions','Go to Addons'=>'Accéder aux extensions','The SEO Pack add-on allows translation of all the URL slugs:'=>'L’extension SEO Pack permet de traduire tous les slugs d’URL :','Taxonomy slugs'=>'Slugs de taxonomie','Term slugs'=>'Slugs de termes','Post slugs (this includes pages and custom post types)'=>'Slugs d’articles (cela comprend les pages et les types de contenu personnalisés)','Post type base slugs'=>'Slugs de base de type de contenu','WooCommerce slugs'=>'Slugs WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'L\'extension SEO Pack est disponible avec TOUTES les versions premium de l\'extension.','Upgrade to Pro'=>'Passer à la version Pro','Description'=>'Description','Article Section'=>'Section d\'article','Article Tag'=>'Étiquette de publication','OG Title'=>'Titre OG','OG Site Name'=>'Nom du site OG','OG Description'=>'Description OG','OG Image Alt'=>'Texte alternatif de l\'image OG','Twitter Title'=>'Titre Twitter','Twitter Description'=>'Description Twitter','Twitter Image Alt'=>'Texte alternatif de l\'image Twitter','Page Title'=>'Titre de la page','Dublin Core Title'=>'Titre Dublin Core','Dublin Core Description'=>'Description Dublin Core','OG Image'=>'Image OG','OG Image Secure URL'=>'URL sécurisée de l\'image OG','Twitter Image'=>'Image Twitter','Removing cdata dictionary strings for language %s...'=>'Suppression des chaînes de dictionnaire cdata pour la langue %s…','Removing untranslated dictionary links for language %s...'=>'Suppression des liens de dictionnaire non traduits pour la langue %s...','Removing duplicated gettext strings for language %s...'=>'Suppression des chaînes Gettext dupliquées pour la langue %s…','Removing duplicated dictionary strings for language %s...'=>'Suppression des chaînes de dictionnaire dupliquées pour la langue %s…','Removing untranslated dictionary strings where translation is available for language %s...'=>'Suppression des chaînes de dictionnaire non traduites pour lesquelles une traduction est disponible pour la langue %s…','Inserting original strings for language %s...'=>'Insérer des chaînes originales pour les langues %s…','Cleaning original strings table for language %s...'=>'Nettoyage de la table de chaînes d’origine pour la langue %s…','Updating original string ids for language %s...'=>'Mise à jour des ID de chaînes originaux pour les langues %s…','Regenerating original meta table for language %s...'=>'Régénération de la table méta originale pour la langue %s...','Cleaning original meta table for language %s...'=>'Nettoyage de la table méta originale pour la langue %s...','Replacing original id NULL with value for language %s...'=>'Remplacement des ID originaux NULL par une valeur pour la langue %s...','Inserting gettext original strings for language %s...'=>'Insertion des chaînes originales Gettext pour la langue %s…','Cleaning gettext original strings table for language %s...'=>'Nettoyage de la table des chaînes originales Gettext pour la langue %s…','Updating gettext original string ids for language %s...'=>'Mise à jour des identifiants des chaînes originales Gettext pour la langue %s…','Migrating taxonomy and post type base slugs to new table structure...'=>'Migration des slugs de taxonomie et de base de type de contenu vers la nouvelle structure de table…','Migrating post slugs to new table structure for language %s...'=>'Migration des slugs d’articles vers la nouvelle structure de table pour la langue %s…','Migrating term slugs to new table structure for language %s...'=>'Migration des slugs de termes vers la nouvelle structure de table pour la langue %s...','Finishing up...'=>'Finalisation…','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'L\'optimisation de la base de données ne s\'est pas terminée correctement. Nous vous recommandons de restaurer la base de données d\'origine ou de <a href="%s" >réessayer.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Mise à jour annulée ! Votre compte utilisateur n’a pas les droits nécessaires pour effectuer les mises à jour de la base de données.','Update aborted! Invalid nonce.'=>'Mise à jour annulée ! Nonce non valide.','Update aborted! Incorrect action.'=>'Mise à jour annulée ! Action incorrecte.','Update aborted! Incorrect language code.'=>'Mise à jour annulée ! Code de langue incorrect.','Updating database to version %s+'=>'Mise à jour de la base de données vers la version %s+','Processing table for language %s...'=>'Traitement des tables pour la langue %s…','Back to TranslatePress Settings'=>'Retour aux réglages de TranslatePress','Successfully updated database!'=>'Base de données bien mise à jour !',' done.'=>' terminé.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Tous les plugins complémentaires individuels de TranslatePress <a href="%1$s" target="_blank">ont été retirés</a> et sont désormais inclus dans les versions premium Personnelle, Entreprise et Développeur de TranslatePress. Veuillez vous connecter à votre <a href="%2$s" target="_blank">page de compte</a>, télécharger la nouvelle version premium et l\'installer. Les paramètres de vos extensions individuelles seront transférés.','Brand-new Language Switcher Settings are here!'=>'Les tout nouveaux réglages du sélecteur de langue sont là !','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Explorez des modèles prédéfinis, changez les couleurs, les styles de drapeaux, l\'espacement, les mises en page et bien plus encore. Utilisez l\'aperçu en direct pour peaufiner votre sélecteur en quelques secondes.','Start customizing'=>'Commencer la personnalisation','Read documentation'=>'Lire la documentation','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> nécessite la <strong><a href="http://php.net/manual/en/book.mbstring.php">bibliothèque Multibyte String PHP</a></strong>. Veuillez contacter votre hébergeur pour l’installer sur votre serveur.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Détection d’une limitation de requêtes longues sur l’hébergement WPEngine. Certaines pages volumineuses peuvent apparaître non traduites. Vous pouvez supprimer cette limitation en ajoutant ce qui suit au fichier wp-config.php de votre site : define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Drapeau de langue personnalisé','The Language code of the added custom language cannot be empty.'=>'Le code de langue de la langue personnalisée ajoutée ne peut pas être vide.','The Language code of the added custom language is invalid.'=>'Le code de langue de la langue personnalisée ajoutée est invalide.','The Automatic Translation Code of the added custom language is invalid.'=>'Le code de traduction automatique de la langue personnalisée ajoutée est invalide.','TranslatePress Add-ons'=>'Modules complémentaires TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Vous devez d’abord acheter cette version pour avoir accès au module complémentaire %1$sici%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Veuillez d’abord %1$ssaisir votre clé de licence%2$s pour activer ce module complémentaire.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Vous avez besoin d’une licence active pour avoir accès au module complémentaire. Renouvelez ou achetez-en une nouvelle %1$sici%2$s.','Advanced Add-ons'=>'Modules complémentaires avancés','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Ces modules améliorent votre extension de traduction et sont disponibles dans les formules Developer, Business et Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Ancien)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Prise en charge du SEO pour le slug de page, le titre de page, la description et les informations du graphique social de Facebook et de Twitter. L’attribut lang HTML est correctement défini.','Multiple Languages'=>'Langues multiples','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Ajoutez autant de langues que nécessaire pour internationaliser votre projet. Publiez votre langue uniquement lorsque toutes vos traductions sont terminées.','Pro Add-ons'=>'Modules complémentaires Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Ces modules améliorent votre extension de traduction et sont disponibles dans les formules Business et Developer.','DeepL Automatic Translation'=>'Traduction automatique DeepL','Automatically translate your website through the DeepL API.'=>'Traduisez automatiquement votre site Web via l’API DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Invite les visiteurs à basculer vers leur langue préférée en fonction des paramètres de leur navigateur ou de leur adresse IP et mémorise la dernière langue visitée.','Translator Accounts'=>'Comptes de traducteur','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Créez des comptes de traducteur pour les nouveaux utilisateurs ou autorisez les utilisateurs existants qui ne sont pas administrateurs à traduire votre site web.','Browse As User Role'=>'Naviguer en tant que rôle utilisateur','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Naviguez sur votre site web comme le ferait un rôle utilisateur particulier. Très utile pour le contenu dynamique ou le contenu masqué qui apparaît pour certains utilisateurs.','Navigation Based on Language'=>'Navigation basée sur la langue','Configure different menu items for different languages.'=>'Configurer différents éléments de menus par langue.','Different Domain per Language'=>'Domaine différent par langue','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Connectez des domaines ou sous-domaines séparés à chacune de vos versions traduites. Renforcez l\'identité locale de votre marque et améliorez les performances SEO pour chaque langue prise en charge.','Recommended Plugins'=>'Extensions recommandées','A short list of plugins you can use to extend your website.'=>'Une courte liste d\'extensions que vous pouvez utiliser pour étendre votre site web.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Capturez plus d\'informations utilisateur sur le formulaire d\'inscription grâce aux champs de profil utilisateur personnalisés de Profile Builder et/ou ajoutez un processus de confirmation par e-mail pour vérifier les comptes de vos clients.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Acceptez les paiements des internautes, créez des offres d’abonnement et restreignez le contenu sur votre site d’adhésion.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Créez des automatisations et des flux de travail sans code sur votre site WordPress. Connectez facilement vos extensions, sites et applications ensemble.','Save Changes'=>'Enregistrer les modifications','TranslatePress Errors'=>'Erreurs TranslatePress','There are no logged errors.'=>'Il n’y a pas d’erreurs enregistrées.','Change language'=>'Changer de langue','Website language selector'=>'Sélecteur de langue du site web','WordPress Translation Plugin'=>'Extension de traduction WordPress','Available languages'=>'Langues disponibles','Language Switcher update notice'=>'Avis de mise à jour du sélecteur de langue','Legacy language switcher is currently enabled'=>'L\'ancien sélecteur de langue est actuellement activé','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Nous avons mis à niveau le sélecteur pour une personnalisation plus riche et une meilleure expérience utilisateur.<br>Pour utiliser le nouveau configurateur, désactivez <strong>Charger l\'ancien sélecteur de langue</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Remarque : vous pouvez rebasculer à tout moment depuis <strong>Réglages avancés → <a href="%s">Dépannage</a></strong>.','Enable the new switcher'=>'Activer le nouveau sélecteur','Your License Key is valid.'=>'Votre clé de licence est valide.','Your License Key is invalid.'=>'Votre clé de licence est invalide.','Your License has expired.'=>'Votre licence a expiré.','Deactivate License'=>'Désactiver la licence','Add a license key'=>'Ajouter une clé de licence','License Key'=>'Clé de licence','Manage your license in your %1$s.'=>'Gérez votre licence dans votre %1$s.','Account Page'=>'Page de compte','Don’t have a TranslatePress AI License Key?'=>'Vous n’avez pas de clé de licence TranslatePress AI ?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Vous pouvez en obtenir une %1$sgratuitement%2$s en créant un compte gratuit. Cela inclut :','Access to TranslatePress AI for instant automatic translations'=>'Accès à TranslatePress AI pour des traductions automatiques instantanées','2000 AI words to translate automatically'=>'2000 mots IA à traduire automatiquement','Get a free License Today'=>'Obtenir une licence gratuite aujourd’hui','Debug Information'=>'Informations de débogage','Debug Data for License Checking'=>'Données de débogage pour la vérification de la licence','Debug Data for License Activation'=>'Données de débogage pour l’activation de la licence','Get more AI words and unlock all features with TranslatePress Pro.'=>'Obtenez plus de mots IA et débloquez toutes les fonctionnalités avec TranslatePress Pro.','Upgrade now ↗'=>'Mettre à niveau maintenant ↗','Already purchased a Premium version?'=>'Vous avez déjà acheté une version Premium ?','Go to your %1$s'=>'Accédez à votre %1$s','TranslatePress.com Account'=>'Compte TranslatePress.com','Download & Install the Pro plugin'=>'Télécharger et installer l\'extension Pro','Learn More'=>'En savoir plus','Get a translation volume estimate with a detailed breakdown per page'=>'Obtenir une estimation du volume de traduction avec un détail par page','Find how many translatable words are on your website'=>'Trouver le nombre de mots traduisibles sur votre site web','Enable Automatic Translation'=>'Activer la traduction automatique','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Pour utiliser <strong>DeepL</strong> pour la traduction automatique, activez cette extension Pro depuis <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'La traduction automatique <strong>DeepL</strong> est disponible comme <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'En effectuant une mise à niveau, vous aurez accès à toutes les extensions payantes, au support premium et vous aiderez à financer le développement futur de TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Veuillez noter que l’utilisation de l’API DeepL est payée séparément. Voir <a href="https://www.deepl.com/pro.html#developer">les informations sur les prix DeepL</a>.','TranslatePress Pro Add-ons'=>'Extensions Pro de TranslatePress','Test API credentials'=>'Tester l’identification de l’API','Check if the selected translation engine is configured correctly.'=>'Vérifiez si le moteur de traduction sélectionné est configuré correctement.','Alternative Engines'=>'Moteurs alternatifs','Switch to TranslatePress AI'=>'Passer à TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Intégrer la traduction automatique directement à votre site web WordPress.','More info'=>'Plus d\'infos','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Choisissez le moteur que vous souhaitez utiliser pour %1$s traduire automatiquement votre site web.','Automatic Translation Settings'=>'Réglages de traduction automatique','AI Words Low Notification'=>'Notification de mots IA faibles','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Recevoir une notification par e-mail lorsque le nombre de mots TranslatePress AI descend en dessous du seuil spécifié.','This feature is only available when using the TranslatePress AI translation engine.'=>'Cette fonctionnalité n\'est disponible qu\'avec le moteur de traduction TranslatePress AI.','Notification Email'=>'E-mail de notification','The email address where the low AI words notification will be sent.'=>'L\'adresse e-mail à laquelle la notification de mots IA faibles sera envoyée.','Word Threshold'=>'Seuil de mots','words'=>'mots','You will be notified when remaining AI words drop below this number.'=>'Vous serez notifié lorsque le nombre de mots IA restants descendra en dessous de ce nombre.','Automatically Translate Slugs'=>'Traduire automatiquement les slugs','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Générer des traductions automatiques de slugs pour les articles, les pages et les types de publication personnalisés.<br/>Les slugs seront automatiquement traduits à partir du deuxième rafraîchissement de chaque page.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Cette fonctionnalité n\'est disponible que dans la version payante. Mettez à niveau TranslatePress et débloquez davantage de fonctionnalités premium.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Nécessite l\'installation et l\'activation de <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">l\'extension SEO Pack</a>.','Upgrade now'=>'Mettre à niveau maintenant','Block Crawlers'=>'Bloquer les robots','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Bloquer les robots d\'exploration pour éviter le déclenchement de traductions automatiques sur votre site.<br>Cela n\'empêchera pas les robots d\'accéder aux pages de ce site.','Limit machine translation / characters per day'=>'Limiter la traduction automatique / caractères par jour','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Ajoutez une limite au nombre de caractères traduits automatiquement afin de mieux gérer le budget de votre projet.','characters per day'=>'caractères par jour','Today\'s Character Count: '=>'Nombre de caractères d\'aujourd\'hui : ','Log machine translation queries.'=>'Enregistrer les requêtes de traduction automatique.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Activer uniquement à des fins de test. Peut affecter les performances.<br>Tous les enregistrements sont stockés dans la table de base de données wp_trp_machine_translation_log. Utilisez une extension comme <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> pour consulter les journaux, ou directement depuis votre gestionnaire de base de données (PHPMyAdmin, etc.).','Test API Credentials'=>'Tester les identifiants d\'API','HTTP Referrer: '=>'Référent HTTP : ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Utilisez ce référent HTTP si l’API vous permet de restreindre l’utilisation de la clé à partir de son tableau de bord.','Response'=>'Réponse','Response Body'=>'Corps de la réponse','Entire Response From wp_remote_get():'=>'Réponse complète de wp_remote_get() :','All Languages'=>'Toutes les langues','Select the languages you wish to make your website available in.'=>'Sélectionnez les langues dans lesquelles vous souhaitez que votre site Web soit disponible.','Formality'=>'Formalité','Code'=>'Code','Slug'=>'Identifiant','Default'=>'Par défaut','Formal'=>'Formel','Informal'=>'Informel','Language'=>'Langue','This language does not support formality. '=>'Cette langue ne prend pas en charge la formalité. ','Are you sure you want to remove this language?'=>'Confirmez-vous vouloir supprimer cette langue ?','Custom Languages'=>'Langues personnalisées','To Add more languages activate the Multiple Languages Addon'=>'Pour ajouter davantage de langues, activez l\'extension Langues multiples','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Vous devez disposer d\'une licence active pour ajouter davantage de langues. Vérifiez dans votre %1$scompte%2$s que votre licence est valide.','Please %1$senter your license%2$s key first to add more languages.'=>'Veuillez d\'abord %1$sentrer votre clé de licence%2$s pour ajouter davantage de langues.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'L\'ajout de plus de deux langues est une fonctionnalité payante. Mettez à niveau TranslatePress et débloquez d\'autres fonctionnalités premium.','Website Languages'=>'Langues du site','Default Language'=>'Langue par défaut','Select the language your content is written in.'=>'Sélectionnez la langue dans laquelle votre contenu est rédigé.','WARNING. Changing the default language will invalidate existing translations.'=>'AVERTISSEMENT : Changer la langue par défaut invalidera les traductions existantes.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Même en passant de en_US à en_GB, car elles sont traitées comme deux langues différentes.','In most cases changing the default flag is all it is needed: '=>'Dans la plupart des cas, il suffit de changer le drapeau par défaut : ','replace the default flag'=>'remplace le drapeau par défaut','Re-run Setup Wizard'=>'Relancer l\'assistant de configuration','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'L\'assistant de configuration vous permet de configurer rapidement TranslatePress. Vous pouvez le lancer à tout moment.','Language Settings'=>'Paramètres de langue','Use Native language name'=>'Utiliser le nom de la langue native','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Cochez cette case si vous souhaitez afficher les langues dans leur nom natif. Sinon, les langues seront affichées en anglais.','Use a subdirectory for the default language'=>'Utiliser un sous-répertoire pour la langue par défaut','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Cochez cette case si vous souhaitez ajouter le sous-répertoire dans l\'URL pour la langue par défaut.</br>En cochant cette option, la langue par défaut vue par les visiteurs du site deviendra la première de la liste « Toutes les langues ».','Force language in custom links'=>'Forcer la langue dans les liens personnalisés','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Sélectionnez Oui si vous souhaitez forcer les liens personnalisés sans codage de langue pour conserver la langue actuellement sélectionnée.','Shortcode '=>'Code court ','Use shortcode on any page or widget.'=>'Utilisez un code court sur n’importe quelle page ou widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Vous pouvez également ajouter le <a href="%s" title="Language Switcher Block Documentation">bloc de sélecteur de langue</a> dans l\'éditeur Gutenberg de WP.','Menu item'=>'Élément de menu','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Aller sur %1$s Apparence -> Menus%2$s pour ajouter un sélecteur de langues dans n’importe quel menu.','Learn more in our documentation.'=>'En savoir plus dans notre documentation.','Floating language selection'=>'Sélecteur de langue flottant','Add a floating dropdown that follows the user on every page.'=>'Ajouter un menu déroulant flottant sur chaque page.','Show "Powered by TranslatePress"'=>'Afficher « Propulsé par TranslatePress »','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Afficher le petit libellé « Propulsé par TranslatePress » dans le sélecteur de langue flottant.','5 Days to Better Multilingual Websites'=>'5 jours pour de meilleurs sites multilingues','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sRejoignez notre cours d\'intégration GRATUIT et EXCLUSIF%s et découvrez comment développer votre trafic multilingue, atteindre les marchés internationaux et gagner du temps et de l\'argent tout en tirant le meilleur parti de TranslatePress !','Invalid email address'=>'Adresse e-mail invalide','Your email'=>'Votre e-mail','Sign me up!'=>'Inscrivez-moi !','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Inscrivez-vous avec votre adresse e-mail et recevez un guide par e-mail en 5 parties pour vous aider à tirer le meilleur parti de TranslatePress.','Dismiss email course notification'=>'Ignorer la notification du cours par e-mail','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Bonjour %s,<br>Ne manquez jamais une mise à jour importante - acceptez nos notifications de mises à jour de sécurité et de fonctionnalités, ainsi que le suivi diagnostique non sensible.','Allow & Continue'=>'Autoriser et continuer','Skip'=>'Passer','This will allow TranslatePress to:'=>'Cela permettra à TranslatePress de :','Your profile overview'=>'Vue d\'ensemble de votre profil','Name and email address'=>'Nom et adresse e-mail','Admin Notices'=>'Notifications d\'administration','Updates, announcements, marketing, no spam'=>'Mises à jour, annonces, marketing, pas de spam','Plugin status & settings'=>'État et réglages de l’extension','Active, Deactivated, installed version and settings'=>'Actif, désactivé, version installée et paramètres','Privacy Policy'=>'Politique de confidentialité','Terms of Service'=>'Conditions d\'utilisation','Support'=>'Assistance','Documentation'=>'Documentation','Add Extra AI Words'=>'Ajouter des mots IA supplémentaires','Optimize TranslatePress database tables'=>'Optimiser les tables de base de données TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>NOTE IMPORTANTE :</strong> Avant d\'effectuer cette action, il est fortement recommandé d\'effectuer d\'abord une sauvegarde de la base de données.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'IMPORTANT : il est vivement recommandé de commencer par sauvegarder la base de données ! \\nVoulez-vous vraiment continuer ?','Operations to perform'=>'Opérations à effectuer','Remove CDATA for original and dictionary strings'=>'Supprimer les sections CDATA des chaînes originales et de dictionnaire','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Supprime les CDATA des tables trp_original_strings et trp_dictionary_*.<br>Ce type de contenu ne devrait pas être détecté par TranslatePress. Il a peut-être été introduit dans la base de données dans d\'anciennes versions de l\'extension.','Remove untranslated links from dictionary tables'=>'Supprimer les liens non traduits des tables de dictionnaire','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Supprime les liens et images non traduits de toutes les tables trp_dictionary_*. Ces tables contiennent les traductions des chaînes saisies par l’utilisateur telles que le contenu d’article, le titre d’article, les menus, etc.','Remove duplicate rows for gettext strings'=>'Supprimer les lignes en double pour les chaînes gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Nettoie toutes les tables trp_gettext_* des lignes en double. Ces tables contiennent les traductions des chaînes de thèmes et d’extensions.','Remove duplicate rows for dictionary strings'=>'Retirer les lignes en doublon pour les chaînes de dictionnaire','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Nettoie toutes les tables trp_dictionary_* des lignes en double. Ces tables contiennent les traductions des chaînes saisies par l’utilisateur telles que le contenu d’article, le titre d’article, les menus, etc.','Remove duplicate rows for original dictionary strings'=>'Supprimer les lignes en double pour les chaînes de dictionnaire originales','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Nettoie toute la table trp_original_strings de ses lignes en double. Cette table contient les chaînes dans la langue par défaut, sans aucune traduction.<br>La table trp_original_meta, qui contient des métadonnées faisant référence à l’ID de l’article parent, est également régénérée.<br>Ces doublons peuvent apparaître dans des situations exceptionnelles de comportement inattendu.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Remplacer les chaînes gettext dont l’ID original est NULL par les ID originaux corrects','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Corrige un problème de cas limite où certaines chaînes gettext ont l’ID original incorrectement défini sur NULL, ce qui provoque des problèmes dans l’éditeur de traduction.<br>Cette opération corrige les ID originaux dans les tables trp_gettext_*.<br>Cochez cette option uniquement si vous avez rencontré un problème dans l’éditeur de traduction où cliquer sur le crayon vert ne faisait pas apparaître la chaîne gettext à traduire dans la barre latérale gauche.<br>Sinon, veuillez laisser cette option décochée car il s’agit d’une opération intensive.','Optimize Database'=>'Optimiser la base de données','TranslatePress Database Updater'=>'Mise à niveau de la base de données TranslatePress','Updating TranslatePress tables. Please leave this window open.'=>'Mise à jour des tables TranslatePress. Veuillez laisser cette fenêtre ouverte.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Les langues inactives resteront visibles et actives pour l\'administrateur. Pour les autres utilisateurs, elles ne seront ni visibles dans les sélecteurs de langue, ni accessibles.','unknown'=>'inconnu','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>L\'extension Extra Languages</strong> nécessite TranslatePress version %1$s ou supérieure. Vous utilisez actuellement la version %2$s. Veuillez mettre à jour TranslatePress pour activer cette fonctionnalité.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Les modifications de traduction de slug automatiques et manuelles effectuées lorsque <strong>TranslatePress - Multilingual</strong> 2.8.4 était actif ont dû être supprimées en raison de certains problèmes avec cette version. Toutes les traductions de slug antérieures à cette version sont désormais utilisées. Merci de votre compréhension !','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Si vous en avez absolument besoin, les traductions supprimées se trouvent dans les tables trp_slug_original_obsolete et trp_slug_translation_obsolete.','View Docs'=>'Voir la documentation','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Attribuez des domaines ou sous-domaines différents à chaque langue. Lorsque les visiteurs accèdent à ces domaines, TranslatePress charge directement la traduction dans la langue appropriée sans redirection.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Exemple : %1$s pour l’anglais, %2$s pour l’espagnol, %3$s pour le français.','Before enabling:'=>'Avant l’activation :','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Assurez-vous que vos domaines sont enregistrés, pointés vers votre serveur et que des certificats SSL sont configurés.','Domain'=>'Domaine','Map this language to a different domain or sub-domain.'=>'Associez cette langue à un domaine ou sous-domaine différent.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Pré-remplir avec le domaine actuel','Check DNS'=>'Vérifier le DNS','Checking DNS...'=>'Vérification du DNS...','DNS is correctly configured!'=>'Le DNS est correctement configuré !','DNS check failed. Please verify your domain configuration.'=>'La vérification du DNS a échoué. Veuillez vérifier la configuration de votre domaine.','This domain is already assigned to another language.'=>'Ce domaine est déjà attribué à une autre langue.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>L’extension Domaine différent par langue</strong> requiert TranslatePress version %1$s ou supérieure. Vous utilisez actuellement la version %2$s. Veuillez mettre à jour TranslatePress pour activer cette fonctionnalité.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Remarque : cette option est désactivée lorsque l’extension Domaine différent par langue est active.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Domaine différent par langue : un domaine est requis lorsque le mappage de domaine est activé. Le commutateur a été désactivé pour les langues dont les domaines sont vides.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Domaine différent par langue : le même domaine ne peut pas être attribué à plusieurs langues. Le commutateur a été désactivé pour les domaines en double.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Domaine différent par langue : le domaine d’une langue ne peut pas être identique à l’URL du site principal. Le commutateur a été désactivé pour le domaine correspondant.','Please enter a domain.'=>'Veuillez saisir un domaine.','Invalid domain format.'=>'Format de domaine invalide.','Could not reach domain: %s'=>'Impossible d\'atteindre le domaine : %s','Domain returned HTTP status %d.'=>'Le domaine a renvoyé le statut HTTP %d.','Domain is reachable!'=>'Le domaine est accessible !','Limit this menu item to the following languages'=>'Limiter cet élément de menu aux langues suivantes','Date format'=>'Format de date','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Personnalisez le format de date pour chaque langue traduite.<br/>Laissez vide pour le réglage WP par défaut ou consultez plus d\'informations <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">ici</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Pour modifier une langue TranslatePress existante, saisissez le code de langue et remplissez uniquement les colonnes que vous souhaitez écraser (par ex. Nom de la langue, Drapeau).<br>Vous pouvez également ajouter de nouvelles langues personnalisées. Elles seront disponibles sous Réglages généraux, liste Toutes les langues, où le slug peut être modifié.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Pour un drapeau personnalisé, téléversez d\'abord l\'image dans la bibliothèque de médias puis collez l\'URL.<br>La modification ou la suppression d\'une langue personnalisée aura un impact sur les traductions et les URL du site.<br>Le code de langue et le code ISO ne doivent contenir que des valeurs alphabétiques, des valeurs numériques, "-" et "_".<br>Les codes ISO sont disponibles sur <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Codes ISO Google</a> et <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">Codes cibles DeepL</a>.','Language code'=>'Code de la langue','Language name'=>'Nom de la langue','Native name'=>'Nom natif','ISO Code'=>'Code ISO','Flag URL'=>'URL du drapeau','Text RTL'=>'Texte RTL','Custom language'=>'Langue personnalisée','Disable dynamic translation'=>'Désactiver la traduction dynamique','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Désactive la détection des chaînes affichées dynamiquement avec du JavaScript.<br/>Les chaînes chargées via un appel AJAX côté serveur seront toujours traduites.','Disable translation for gettext strings'=>'Désactiver la traduction des chaînes gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Les chaînes Gettext sont des chaînes produites par les thèmes et les extensions. <br> Traduire ce type de chaînes via TranslatePress peut être inutile si elles sont déjà traduites via le système de fichiers de traduction .po/.mo.<br>Activer cette option peut améliorer les performances de chargement des pages de votre site dans certains cas. L’inconvénient est que vous ne pourrez plus modifier les traductions Gettext via TranslatePress, ni bénéficier de la traduction automatique pour ces chaînes.','Gettext Strings translation is disabled'=>'La traduction des chaînes Gettext est désactivée','To enable it go to '=>'Pour l\'activer, allez dans ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Réglages avancés->Débogage->Désactiver la traduction des chaînes Gettext',' and uncheck the Checkbox.'=>' et décochez la case à cocher.','Dismiss'=>'Ignorer','Exclude translated links from sitemap'=>'Exclure les liens traduits du sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Ne pas inclure de liens traduits dans les sitemaps générés par les extensions SEO.<br/>Nécessite l\'installation et l\'activation du <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="Documentation du module complémentaire SEO Pack de TranslatePress" target="_blank"> module complémentaire SEO Pack</a>.','Disable post container tags for post title'=>'Désactiver les balises conteneur d’article pour le titre de l’article','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Cela désactive l’indexation du titre de l’article dans les langues traduites.<br/>Utile lorsque le titre de l’article n’autorise pas le HTML, ce qui provoque un affichage incorrect de la page.','Disable post container tags for post content'=>'Désactiver les balises conteneur d’article pour le contenu de l’article','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Cela désactive l’indexation du contenu de l’article dans les langues traduites.<br/>Utile lorsque le contenu de l’article n’autorise pas le HTML, ce qui provoque un affichage incorrect de la page.','Do not translate certain paths'=>'Ne pas traduire certains chemins','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Choisissez quels chemins peuvent être traduits. Prend en charge le caractère générique à la fin du chemin.<br>Par exemple, pour exclure https://example.com/some/path, vous pouvez utiliser la règle /some/path/ ou /some/*.<br>Saisissez chaque règle sur sa propre ligne. Pour exclure la page d\'accueil, utilisez {home}.','Exclude Paths From Translation'=>'Exclure les chemins de la traduction','Translate Only Certain Paths'=>'Traduire uniquement certains chemins','Enable the hreflang x-default tag for language:'=>'Activer la balise hreflang x-default pour la langue :','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Active la balise hreflang="x-default" pour une langue entière. Voir la documentation pour plus de détails.','Translate numbers and numerals'=>'Traduire les nombres et les numéraux','Enable translation of numbers ( e.g. phone numbers)'=>'Activer la traduction des nombres (par ex. les numéros de téléphone)','Selector'=>'Sélecteur','Exclude from dynamic translation'=>'Exclure de la traduction dynamique','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Ne traduisez pas de manière dynamique les chaînes trouvées dans les nœuds HTML correspondant à ces sélecteurs.<br>Exclut tous les enfants de nœuds HTML correspondant à ces sélecteurs de la traduction avec du JavaScript.<br/>Si possible, ces chaînes seront toujours traduites côté serveur.','Gettext String'=>'Chaîne gettext','Exclude Gettext Strings'=>'Exclure les chaînes Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Excluez ces chaînes de la traduction en chaînes Gettext par TranslatePress. Laissez le domaine vide pour prendre en compte toute chaîne Gettext.<br/>Cela peut toujours être traduit à l’aide de fichiers po/mo.','Exclude selectors only from automatic translation'=>'Exclure les sélecteurs uniquement de la traduction automatique','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Ne pas traduire automatiquement les chaînes présentes dans les nœuds HTML correspondant à ces sélecteurs.<br>Exclut tous les enfants des nœuds HTML correspondant à ces sélecteurs de la traduction automatique.<br>La traduction manuelle de ces chaînes reste possible.','Exclude selectors from translation'=>'Exclure les sélecteurs de la traduction','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Ne pas traduire les chaînes présentes dans les nœuds HTML correspondant à ces sélecteurs.<br>Exclut tous les enfants des nœuds HTML correspondant à ces sélecteurs de la traduction.<br>Ces chaînes ne peuvent être traduites ni manuellement ni automatiquement.','String'=>'Chaîne','Exclude strings from automatic translation'=>'Exclure ces chaînes de la traduction automatique','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Ne traduisez pas automatiquement ces chaînes (ex. Noms, mots techniques...)<br>Les paragraphes contenant ces chaînes seront toujours traduits, à l’exception d’une partie spécifiée.','Fix broken HTML'=>'Corriger le HTML cassé','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Tentative générale de correction du HTML cassé ou manquant sur les pages traduites.<br/>','Force slash at end of home url:'=>'Forcer le slash à la fin de l\'URL d\'accueil :','Ads a slash at the end of the home_url() function'=>'Ajoute un slash à la fin de la fonction home_url()','Show Both (recommended)'=>'Afficher les deux (recommandé)','Remove Country Locale'=>'Supprimer la locale du pays','Remove Region Independent Locale'=>'Supprimer la locale indépendante de la région','Remove duplicate hreflang'=>'Retirer les doublons hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Choisissez les balises hreflang qui apparaîtront sur votre site.<br/>Nous recommandons d\'afficher les deux types de balises hreflang comme l\'indique la <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">documentation Google</a>.<br/>La suppression de la locale de pays lorsque vous avez plusieurs locales de pays de la même langue (p. ex. English UK et English US) entraînera l\'affichage d\'une seule balise hreflang avec un lien vers une seule des locales régionales pour cette langue.','Default (example: en-US, fr-CA, etc.)'=>'Par défaut (exemple : en-US, fr-CA, etc.)','Regional (example: en, fr, es, etc.)'=>'Régional (exemple : en, fr, es, etc.)','HTML Lang Attribute Format'=>'Format d’attribut HTML Lang','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Modifiez l’attribut lang de la balise HTML par un format qui inclut le pays régional ou non. <br>En HTML, l’attribut lang (<html lang="en-US">) doit être utilisé pour spécifier la langue du contenu textuel afin que le navigateur puisse afficher ou traiter correctement votre contenu (par exemple, pour la césure, le style, la vérification orthographique, etc.).','Load legacy Language Switcher'=>'Charger l\'ancien sélecteur de langue','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'S\'applique à tous les types de sélecteurs de langue (flottant, shortcode et menu). Lorsqu\'elle est activée, le site reviendra à l\'utilisation du sélecteur de langue original configuré dans l\'onglet Réglages généraux, en remplaçant la nouvelle version personnalisable. Les réglages existants de votre sélecteur resteront enregistrés, mais ils seront ignorés tant que cette option est active.','Load legacy SEO Pack Add-On'=>'Charger l\'ancienne extension SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Si la récente migration vers la nouvelle réécriture de slug pose problème, définissez cette option sur Oui pour utiliser l\'ancienne méthode.<br> Veuillez <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">ouvrir un ticket de support</a> pour nous informer des problèmes que vous rencontrez.','Manual Translation Only'=>'Traduction manuelle uniquement','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress analyse et enregistre de manière proactive les chaînes dans la base de données lorsque les utilisateurs accèdent aux pages traduites. <br>Ce réglage désactive cette fonctionnalité et n’autorise la traduction et l’enregistrement des chaînes que dans l’éditeur de traduction. <br>Désactive également la traduction automatique en dehors de l’éditeur de traduction, ce qui vous permet de mieux contrôler la consommation de caractères en ne traduisant que les pages que vous visitez dans l’éditeur de traduction.','Open language switcher only on click'=>'Ouvrir le sélecteur de langue uniquement au clic','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Ouvrez le sélecteur de langue shortcode en cliquant dessus au lieu de le survoler.<br> Fermez-le en cliquant dessus, n\'importe où ailleurs sur l\'écran ou en appuyant sur la touche Échap. Cela n\'affectera que le sélecteur de langue shortcode.','Show opposite language in the language switcher'=>'Afficher la langue opposée dans le sélecteur de langue','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Transforme le sélecteur de langue en un bouton affichant l\'autre langue disponible, pas la langue actuelle.<br> Ne fonctionne que lorsqu\'il y a exactement deux langues, la langue par défaut et une langue de traduction.<br>Cela affectera également le sélecteur de langue shortcode et le sélecteur de langue flottant.<br> Pour obtenir ce résultat dans le sélecteur de langue du menu, allez dans Apparence->Menus->Sélecteur de langue et sélectionnez Langue opposée.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Cliquez ici</a> pour accéder à l\'outil d\'optimisation de la base de données.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Cela permet de supprimer d\'éventuelles traductions en double, d\'effacer les données inutiles et de réparer d\'éventuels problèmes de métadonnées.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Ici</a> vous pouvez consulter les 5 dernières erreurs SQL relatives à TranslatePress s\'il en existe.','Troubleshooting'=>'Dépannage','Exclude Gettext strings'=>'Exclure les chaînes Gettext','Debug'=>'Débogage','Custom languages'=>'Langues personnalisées','Miscellaneous options'=>'Options diverses','Exclude strings & pages'=>'Exclure les chaînes et les pages','Automatic Translation Memory'=>'Mémoire de traduction automatique','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Proposer la même traduction pour un texte similaire. Les chaînes doivent présenter un taux de similitude de 95 %.<br>Permet d\'éviter de perdre la traduction existante lors de la correction de fautes de frappe ou d\'ajustements mineurs apportés au texte original. <br>Si une traduction existe déjà pour une chaîne originale très similaire, elle sera automatiquement utilisée pour la chaîne originale actuelle.<br>Ne fonctionne pas lors de la modification d\'un texte faisant partie d\'un bloc de traduction, sauf si le nouveau texte est manuellement fusionné à nouveau dans un bloc de traduction.<br>Chaque chaîne doit comporter un minimum de 50 caractères.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'AVERTISSEMENT : Cette fonctionnalité peut affecter négativement les temps de chargement des pages dans les langues secondaires, particulièrement avec de grandes bases de données (par exemple des sites web comportant beaucoup de pages ou de produits). Si vous rencontrez des temps de chargement lents, désactivez-la et réessayez.','Fix missing dynamic content'=>'Corriger le contenu dynamique manquant','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Peut aider à corriger le contenu manquant inséré à l’aide de JavaScript.<br>Affiche le contenu inséré dynamiquement dans la langue d’origine pendant un moment avant que la demande de traduction ne soit terminée.','Filter Gettext wrapping from post content and title'=>'Filtrez les conteneurs Gettext du contenu et du titre de la publication','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtre l\'encapsulation Gettext telle que #!trpst#trp-gettext du contenu et du titre de tous les articles mis à jour. N\'affecte pas le contenu existant. <br/><strong>La sauvegarde de la base de données est recommandée avant d\'activer cette option.</strong>','Filter Gettext wrapping from post meta'=>'Filtrer les conteneurs Gettext des métas de publication','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtre l\'encapsulation Gettext telle que #!trpst#trp-gettext de toutes les métadonnées des articles mis à jour. N\'affecte pas les métadonnées existantes. <br/><strong>La sauvegarde de la base de données est recommandée avant d\'activer cette option.</strong>','Google Translate v2'=>'Google Traduction v2','Google Translate API Key'=>'Clé API Google Traduction','Add your API Key here...'=>'Ajoutez votre clé API ici...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Visitez <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">ce lien</a> pour voir comment vous pouvez configurer une clé API, <strong>contrôler les tarifs de l’API</strong> et définir les restrictions de référent HTTP.','Your HTTP referrer is: %s'=>'Votre référant HTTP est : %s','There was an error on the server processing your Google Translate key.'=>'Une erreur s\'est produite sur le serveur lors du traitement de votre clé Google Translate.','There was an error with your Google Translate key.'=>'Une erreur s\'est produite avec votre clé Google Translate.','Please check your TranslatePress license key.'=>'Veuillez vérifier votre clé de licence TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Aucune licence active détectée pour ce site web.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Pour activer la traduction automatique à l\'aide de TranslatePress AI, vous devez créer un compte gratuit pour obtenir une clé de licence.','Create your Free Account'=>'Créez votre compte gratuit',' or '=>' ou ','Enter your license key'=>'Saisissez votre clé de licence',' Or %1$spurchase one here%2$s'=>' Ou %1$sachetez-en une ici%2$s','Your free account includes: '=>'Votre compte gratuit comprend : ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Obtenez plus de mots IA et débloquez toutes les fonctionnalités IA avec TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Vous avez une <strong>licence</strong> %s valide.',' words remaining. '=>' mots restants. ','Recheck'=>'Revérifier','Rechecking...'=>'Nouvelle vérification…','Done.'=>'Terminé.','Manage your license & quota on the %s'=>'Gérez votre licence et votre quota sur la %s','TranslatePress.com Account Page'=>'Page de compte TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Prise en charge SEO pour le slug, le titre de la page, la description et les informations du social graph Facebook et Twitter. L\'attribut lang HTML est correctement défini.','Enable Modules'=>'Activer les modules','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Activez les modules complémentaires pour étendre TranslatePress et améliorer les fonctionnalités de votre site traduit.','More functionality with TranslatePress Pro.'=>'Plus de fonctionnalités avec TranslatePress Pro.','Already a Pro User?'=>'Déjà utilisateur Pro ?','Activate License Key'=>'Activer la clé de licence','This add-on is not available on your current plan.'=>'Ce module complémentaire n\'est pas disponible dans votre forfait actuel.','Continue'=>'Continuer','The link you followed has expired. Please reload the page and try again.'=>'Le lien que vous avez suivi a expiré. Veuillez recharger la page et réessayer.','A valid license is required to enable Automatic Translation.'=>'Une licence valide est requise pour activer la traduction automatique.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Votre clé de licence est désactivée pour cette URL. Réactivez-la depuis <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Gérer les sites.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Incompatibilité de clé de licence.</strong> La licence que vous avez saisie ne correspond pas à la version de TranslatePress que vous avez installée.</p><p>Veuillez vérifier que vous avez installé la version correcte pour votre licence depuis votre compte TranslatePress.</p>